    // Listen for contract events
    listenToEvent(contractName, eventName, callback, filter = {}) {
        const contract = this.getContract(contractName);

        const eventFilter = contract.filters[eventName]
            ? contract.filters[eventName](...Object.values(filter))
            : eventName;

        contract.on(eventFilter, (...args) => {
            const event = args[args.length - 1]; // Last arg is the event object
            callback({
                eventName,
                args: args.slice(0, -1),
                blockNumber: event.log?.blockNumber,
                transactionHash: event.log?.transactionHash,
                raw: event
            });
        });

        console.log(`Listening for "${eventName}" events on "${contractName}"`);

        return () => {
            contract.off(eventFilter);
            console.log(`Stopped listening for "${eventName}" events`);
        };
    }

    // Query past events
    async queryEvents(contractName, eventName, fromBlock = 0, toBlock = 'latest') {
        const contract = this.getContract(contractName);

        const filter = contract.filters[eventName]();
        const events = await contract.queryFilter(filter, fromBlock, toBlock);

        return events.map(event => ({
            eventName: event.eventName || eventName,
            args: event.args ? Object.fromEntries(
                event.args.map((val, i) => [
                    event.fragment?.inputs[i]?.name || `arg${i}`,
                    val.toString()
                ])
            ) : {},
            blockNumber: event.blockNumber,
            transactionHash: event.transactionHash,
            logIndex: event.index
        }));
    }

